-- NutriDecrypte , top 50 additives seed (most common in French supermarket products)
-- Source tags: EFSA reevaluation register + ANSES opinions + EU regulation banning list
-- 2026-04-22, v1

on conflict (e_number) do update set
  name_en = excluded.name_en,
  name_fr = excluded.name_fr,
  category = excluded.category,
  risk_level = excluded.risk_level,
  controversy = excluded.controversy,
  banned_in = excluded.banned_in,
  summary_en = excluded.summary_en,
  summary_fr = excluded.summary_fr,
  updated_at = now();
