insert into public.additives (e_number, slug, name_en, name_fr, category, risk_level, controversy, banned_in, summary_en, summary_fr) values
  ('E100', 'e100-curcumin', 'Curcumin', 'Curcumine', 'colourant', 'low', false, '{}', 'Natural yellow from turmeric root. EFSA 2010 reevaluation: safe at current use levels.', 'Colorant jaune naturel extrait du curcuma. Reevaluation EFSA 2010 : sans danger aux doses actuelles.'),
  ('E102', 'e102-tartrazine', 'Tartrazine', 'Tartrazine', 'colourant', 'high', true, '{}', 'Synthetic yellow azo dye. Linked to hyperactivity in children (Southampton study). Mandatory warning on UK labels.', 'Colorant jaune azoique de synthese. Lie a l''hyperactivite chez l''enfant (etude Southampton). Avertissement obligatoire sur etiquettes.'),
  ('E104', 'e104-quinoline-yellow', 'Quinoline Yellow', 'Jaune de quinoleine', 'colourant', 'high', true, '{"US"}', 'Synthetic yellow. Banned in US food products. EU mandatory hyperactivity warning.', 'Jaune de synthese. Interdit dans l''alimentaire aux Etats-Unis. Avertissement hyperactivite UE.'),
  ('E110', 'e110-sunset-yellow', 'Sunset Yellow FCF', 'Jaune orange S', 'colourant', 'high', true, '{}', 'Synthetic orange dye. Southampton study hyperactivity link. EFSA reduced ADI in 2014.', 'Colorant orange synthetique. Lien avec hyperactivite (etude Southampton). DJA reduite par EFSA en 2014.'),
  ('E120', 'e120-carmin', 'Cochineal / Carmine', 'Carmin de cochenille', 'colourant', 'medium', false, '{}', 'Red dye from cochineal insects. Safe but common allergen. Not vegan.', 'Colorant rouge issu d''insectes cochenille. Sans danger mais allergene courant. Non vegan.'),
  ('E122', 'e122-azorubine', 'Azorubine / Carmoisine', 'Azorubine', 'colourant', 'high', true, '{"US", "Japan", "Norway"}', 'Azo dye banned in US, Japan, Norway. EU hyperactivity warning required.', 'Azoique interdit aux Etats-Unis, au Japon, en Norvege. Avertissement hyperactivite en UE.'),
  ('E124', 'e124-ponceau-4r', 'Ponceau 4R', 'Rouge cochenille A', 'colourant', 'high', true, '{"US", "Norway"}', 'Azo dye banned in US and Norway. Hyperactivity warning in EU.', 'Azoique interdit aux Etats-Unis et en Norvege. Avertissement hyperactivite en UE.'),
  ('E129', 'e129-allura-red', 'Allura Red AC', 'Rouge allura', 'colourant', 'high', true, '{"Norway"}', 'Synthetic red common in sweets and cereals. Mandatory warning on EU labels.', 'Rouge synthetique courant dans bonbons et cereales. Avertissement obligatoire en UE.'),
  ('E150a', 'e150a-caramel-plain', 'Plain Caramel', 'Caramel simple E150a', 'colourant', 'low', false, '{}', 'Made by heating carbohydrates. Safe. Common in spirits, vinegars.', 'Obtenu par chauffage des sucres. Sans danger. Courant dans spiritueux, vinaigres.'),
  ('E150c', 'e150c-ammonia-caramel', 'Ammonia Caramel', 'Caramel ammoniacal E150c', 'colourant', 'medium', true, '{}', 'Contains 2-MeI and 4-MeI, classified possibly carcinogenic. EFSA reduced limits 2023.', 'Contient 2-MeI et 4-MeI classes possiblement cancerogenes. Limites EFSA reduites en 2023.'),
  ('E150d', 'e150d-sulphite-ammonia-caramel', 'Sulphite Ammonia Caramel', 'Caramel sulfite ammoniacal E150d', 'colourant', 'medium', true, '{}', 'Used in colas. Contains 4-MeI classified possibly carcinogenic. California Prop 65 warning.', 'Utilise dans sodas colas. Contient 4-MeI classe possiblement cancerogene. Avertissement Prop 65 en Californie.'),
  ('E171', 'e171-titanium-dioxide', 'Titanium Dioxide', 'Dioxyde de titane', 'colourant', 'high', true, '{"EU food"}', 'Banned in EU food since August 2022 (EFSA genotoxicity concerns). Still allowed in medicines.', 'Interdit dans l''alimentation UE depuis aout 2022 (genotoxicite selon EFSA). Toujours autorise en medicaments.'),
  ('E200', 'e200-sorbic-acid', 'Sorbic Acid', 'Acide sorbique', 'preservative', 'low', false, '{}', 'Common fungicide in cheeses, baked goods. EFSA 2019: safe at current levels.', 'Antifongique courant dans fromages et patisseries. Sans danger aux doses actuelles (EFSA 2019).'),
  ('E211', 'e211-sodium-benzoate', 'Sodium Benzoate', 'Benzoate de sodium', 'preservative', 'medium', true, '{}', 'Preservative. Forms benzene when mixed with vitamin C (E300). EFSA under review.', 'Conservateur. Forme du benzene au contact de la vitamine C (E300). Sous revision EFSA.'),
  ('E220', 'e220-sulphur-dioxide', 'Sulphur Dioxide', 'Anhydride sulfureux', 'preservative', 'medium', false, '{}', 'Common in wine, dried fruit. Must be declared on labels (allergen). Asthma trigger.', 'Courant dans vin, fruits secs. Etiquetage obligatoire (allergene). Declencheur d''asthme.'),
  ('E249', 'e249-potassium-nitrite', 'Potassium Nitrite', 'Nitrite de potassium', 'preservative', 'high', true, '{}', 'Used in cured meats. IARC 2015: processed meat is Group 1 carcinogen. France reducing limits 2025.', 'Utilise dans charcuterie. IARC 2015 : viande transformee cancerigene groupe 1. Limites francaises reduites en 2025.'),
  ('E250', 'e250-sodium-nitrite', 'Sodium Nitrite', 'Nitrite de sodium', 'preservative', 'high', true, '{}', 'Cured meat preservative. Forms nitrosamines. France Plan de reduction 2023-2027.', 'Conservateur charcuterie. Forme des nitrosamines. Plan francais de reduction 2023-2027.'),
  ('E251', 'e251-sodium-nitrate', 'Sodium Nitrate', 'Nitrate de sodium', 'preservative', 'high', true, '{}', 'Converted to nitrite in body. Same health concerns as E250.', 'Transforme en nitrite dans l''organisme. Memes preoccupations que E250.'),
  ('E252', 'e252-potassium-nitrate', 'Potassium Nitrate', 'Nitrate de potassium', 'preservative', 'high', true, '{}', 'Salpeter. Used in cured meats. Same risk profile as E251.', 'Salpetre. Utilise dans charcuterie. Meme profil de risque que E251.'),
  ('E300', 'e300-ascorbic-acid', 'Ascorbic Acid', 'Acide ascorbique (vitamine C)', 'antioxidant', 'low', false, '{}', 'Vitamin C. Safe. But forms benzene with E211.', 'Vitamine C. Sans danger. Mais forme du benzene avec E211.'),
  ('E320', 'e320-bha', 'Butylated Hydroxyanisole (BHA)', 'BHA butylhydroxyanisole', 'antioxidant', 'high', true, '{"Japan"}', 'Banned in Japan. California Prop 65 listed as possible carcinogen. EFSA reduced ADI.', 'Interdit au Japon. Inscrit Prop 65 Californie comme cancerogene possible. DJA reduite par EFSA.'),
  ('E321', 'e321-bht', 'Butylated Hydroxytoluene (BHT)', 'BHT butylhydroxytoluene', 'antioxidant', 'high', true, '{}', 'Synthetic antioxidant in cereals, gums. Reproductive toxicity at high doses.', 'Antioxydant synthetique dans cereales et chewing-gums. Toxicite reproductive a haute dose.'),
  ('E330', 'e330-citric-acid', 'Citric Acid', 'Acide citrique', 'acidulant', 'low', false, '{}', 'Safe. Naturally present in citrus. Produced industrially from Aspergillus niger.', 'Sans danger. Naturel dans les agrumes. Produit industriellement par Aspergillus niger.'),
  ('E407', 'e407-carrageenan', 'Carrageenan', 'Carraghenanes', 'thickener', 'medium', true, '{"Infant formula US"}', 'Seaweed extract. Degraded form (poligeenan) is carcinogenic. US bans in infant formula.', 'Extrait d''algues. La forme degradee (poligeenane) est cancerogene. Interdit aux Etats-Unis dans laits infantiles.'),
  ('E412', 'e412-guar-gum', 'Guar Gum', 'Gomme de guar', 'thickener', 'low', false, '{}', 'Vegetable gum. Safe thickener. Fibre source.', 'Gomme vegetale. Epaississant sans danger. Source de fibres.'),
  ('E415', 'e415-xanthan-gum', 'Xanthan Gum', 'Gomme xanthane', 'thickener', 'low', false, '{}', 'Fermentation product. Safe. Common in gluten-free products.', 'Produit de fermentation. Sans danger. Courant dans produits sans gluten.'),
  ('E420', 'e420-sorbitol', 'Sorbitol', 'Sorbitol', 'sweetener', 'low', false, '{}', 'Sugar alcohol. Laxative effect at high doses (mandatory EU warning).', 'Polyol. Effet laxatif a forte dose (avertissement UE obligatoire).'),
  ('E422', 'e422-glycerol', 'Glycerol', 'Glycerol', 'humectant', 'low', false, '{}', 'Also known as glycerin. Safe humectant.', 'Aussi appele glycerine. Humectant sans danger.'),
  ('E440', 'e440-pectin', 'Pectin', 'Pectines', 'gelling agent', 'low', false, '{}', 'From apples, citrus peel. Safe fibre. Common in jams.', 'Extrait de pommes, pelures d''agrumes. Fibre sans danger. Courant dans confitures.'),
  ('E450', 'e450-diphosphates', 'Diphosphates', 'Diphosphates', 'emulsifier', 'medium', true, '{}', 'High consumption linked to cardiovascular risk (ANSES 2020). Ubiquitous in processed foods.', 'Consommation elevee liee au risque cardiovasculaire (ANSES 2020). Ubiquitaire dans aliments transformes.'),
  ('E451', 'e451-triphosphates', 'Triphosphates', 'Triphosphates', 'emulsifier', 'medium', true, '{}', 'Phosphate additive, same concerns as E450.', 'Additif phosphate, memes preoccupations que E450.'),
  ('E452', 'e452-polyphosphates', 'Polyphosphates', 'Polyphosphates', 'emulsifier', 'medium', true, '{}', 'Phosphate additive, same concerns as E450.', 'Additif phosphate, memes preoccupations que E450.'),
  ('E466', 'e466-cmc', 'Sodium Carboxymethylcellulose', 'Carboxymethylcellulose sodique', 'thickener', 'medium', true, '{}', 'Emulsifier. Mouse studies link to gut microbiome disruption. INSERM NutriNet-Sante associates with IBD.', 'Emulsifiant. Etudes murines : perturbation du microbiote. NutriNet-Sante associe a MICI.'),
  ('E471', 'e471-mono-diglycerides', 'Mono- and Diglycerides of Fatty Acids', 'Mono-diglycerides d''acides gras', 'emulsifier', 'medium', true, '{}', 'May contain trans fats. May be of animal origin (not labelled). ANSES studying cardiovascular effects.', 'Peut contenir des acides gras trans. Origine animale possible (non etiquetee). ANSES etudie effets cardiovasculaires.'),
  ('E472e', 'e472e-datem', 'Mono-diglyceride Esters (DATEM)', 'Esters diacetyltartriques', 'emulsifier', 'medium', false, '{}', 'Common in industrial bread. EFSA 2017: no safety concern at current use.', 'Courant dans pain industriel. EFSA 2017 : aucune preoccupation aux doses actuelles.'),
  ('E500', 'e500-sodium-carbonates', 'Sodium Carbonates', 'Carbonates de sodium', 'raising agent', 'low', false, '{}', 'Baking soda family. Safe.', 'Famille du bicarbonate. Sans danger.'),
  ('E621', 'e621-msg', 'Monosodium Glutamate (MSG)', 'Glutamate monosodique', 'flavour enhancer', 'medium', true, '{}', 'EFSA 2017 reduced ADI to 30 mg/kg body weight. Headaches reported at high intake.', 'EFSA 2017 : DJA reduite a 30 mg/kg. Maux de tete rapportes a forte dose.'),
  ('E631', 'e631-disodium-inosinate', 'Disodium Inosinate', 'Inosinate disodique', 'flavour enhancer', 'medium', false, '{}', 'Enhances MSG effect. Often of animal origin (labelling not explicit).', 'Amplifie effet du glutamate. Souvent d''origine animale (etiquetage flou).'),
  ('E635', 'e635-ribonucleotides', 'Disodium Ribonucleotides', 'Ribonucleotides disodiques', 'flavour enhancer', 'medium', false, '{}', 'Synergist with MSG. Eczema reports.', 'Synergique avec glutamate. Rapports d''eczema.'),
  ('E950', 'e950-acesulfame-k', 'Acesulfame K', 'Acesulfame K', 'sweetener', 'medium', true, '{}', '200x sweeter than sugar. EFSA under review 2024.', '200x plus sucrant que le sucre. Reexamine par EFSA en 2024.'),
  ('E951', 'e951-aspartame', 'Aspartame', 'Aspartame', 'sweetener', 'high', true, '{}', 'IARC 2023 classified as possibly carcinogenic to humans (Group 2B).', 'Classe en juillet 2023 par IARC comme possiblement cancerogene pour l''humain (groupe 2B).'),
  ('E952', 'e952-cyclamate', 'Cyclamate', 'Cyclamate', 'sweetener', 'high', true, '{"US"}', 'Banned in US since 1970 (bladder cancer in rats). Still allowed in EU at reduced ADI.', 'Interdit aux Etats-Unis depuis 1970 (cancer vessie chez rat). Autorise en UE a DJA reduite.'),
  ('E953', 'e953-isomalt', 'Isomalt', 'Isomalt', 'sweetener', 'low', false, '{}', 'Sugar alcohol. Mandatory laxative warning.', 'Polyol. Avertissement laxatif obligatoire.'),
  ('E955', 'e955-sucralose', 'Sucralose', 'Sucralose', 'sweetener', 'medium', true, '{}', '600x sweeter than sugar. 2023 studies suggest microbiome disruption and DNA damage.', '600x plus sucrant que le sucre. Etudes 2023 : perturbation du microbiote et degats ADN.'),
  ('E960', 'e960-steviol-glycosides', 'Steviol Glycosides', 'Glycosides de steviol', 'sweetener', 'low', false, '{}', 'Plant-based sweetener. EFSA 2010: safe.', 'Edulcorant d''origine vegetale. Sans danger (EFSA 2010).'),
  ('E961', 'e961-neotame', 'Neotame', 'Neotame', 'sweetener', 'medium', false, '{}', '7000 to 13000x sweeter than sugar. 2024 studies suggest gut barrier damage.', '7000 a 13000x plus sucrant que le sucre. Etudes 2024 : atteinte barriere intestinale.'),
  ('E965', 'e965-maltitol', 'Maltitol', 'Maltitol', 'sweetener', 'low', false, '{}', 'Sugar alcohol. Mandatory laxative warning.', 'Polyol. Avertissement laxatif obligatoire.'),
  ('E967', 'e967-xylitol', 'Xylitol', 'Xylitol', 'sweetener', 'low', false, '{}', 'Sugar alcohol. Good for dental health. Toxic to dogs.', 'Polyol. Bon pour la sante dentaire. Toxique pour les chiens.'),
  ('E968', 'e968-erythritol', 'Erythritol', 'Erythritol', 'sweetener', 'medium', true, '{}', '2023 study (Nature Medicine): linked to cardiovascular events. Additional research ongoing.', 'Etude 2023 (Nature Medicine) : lien avec evenements cardiovasculaires. Recherches en cours.'),
  ('E1520', 'e1520-propylene-glycol', 'Propylene Glycol', 'Propylene glycol', 'humectant', 'low', false, '{}', 'Safe at regulated doses. EFSA 2018: acceptable daily intake reaffirmed.', 'Sans danger aux doses reglementees. EFSA 2018 : DJA reconfirmee.')
